export const LANGUAGE_CATALOG = CATALOG.languages;
export const LANGUAGE_ALIAS_TO_CODE = Object.freeze(CATALOG.aliasToCode);
export const LANGUAGE_BY_CODE = Object.freeze(CATALOG.byCode);
export const LANGUAGE_BY_API_VALUE = Object.freeze(CATALOG.byApiValue);
export const FRONTEND_LANGUAGES = Object.freeze(CATALOG.frontendLanguages);
export const BACKEND_UI_LANGUAGES = Object.freeze(CATALOG.backendUiLanguages);
export const CUSTOMER_CONTENT_LANGUAGES = Object.freeze(CATALOG.customerContentLanguages);
export const FRONTEND_LANGUAGE_CODES = Object.freeze(FRONTEND_LANGUAGES.map((entry) => entry.code));
export const BACKEND_UI_LANGUAGE_CODES = Object.freeze(BACKEND_UI_LANGUAGES.map((entry) => entry.code));
export const CUSTOMER_CONTENT_LANGUAGE_CODES = Object.freeze(CUSTOMER_CONTENT_LANGUAGES.map((entry) => entry.code));
export const LANGUAGE_API_VALUES = Object.freeze(LANGUAGE_CATALOG.map((entry) => entry.apiValue));

export function languageByCode(code) {
  const normalized = String(code || "").trim().toLowerCase();
  return LANGUAGE_BY_CODE[normalized] || null;
}

export function languageByApiValue(value) {
  const normalized = String(value || "").trim();
  return LANGUAGE_BY_API_VALUE[normalized] || null;
}

export function normalizeLanguageCode(value, { allowedCodes = CUSTOMER_CONTENT_LANGUAGE_CODES, fallback = "en" } = {}) {
  const normalized = String(value || "").trim().toLowerCase();
  const resolved = LANGUAGE_ALIAS_TO_CODE[normalized] || null;
  const allowed = Array.isArray(allowedCodes) ? allowedCodes : CUSTOMER_CONTENT_LANGUAGE_CODES;
  if (resolved && allowed.includes(resolved)) return resolved;
  if (allowed.includes(normalized)) return normalized;
  return allowed.includes(fallback) ? fallback : (allowed[0] || "en");
}

export function apiValueFromLanguageCode(code, fallback = "English") {
  return languageByCode(code)?.apiValue || fallback;
}

export function promptLanguageName(code, fallback = "English") {
  return languageByCode(code)?.promptName || fallback;
}

export function pdfLocaleForLanguage(code, fallback = "en-GB") {
  return languageByCode(code)?.pdfLocale || fallback;
}

export function languageDirection(code, fallback = "ltr") {
  return languageByCode(code)?.direction || fallback;
}

export function isRtlLanguage(code) {
  return languageDirection(code) === "rtl";
}
